Here is a complete, self-contained HTML file that uses **Three.js** to render a 3D house. You can save this code as an `.html` file (e.g., `house.html`) and open it in any modern web browser.

### The Code

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Drag to Rotate • Scroll to Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const floorMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 }); // Green grass
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.PlaneGeometry(100, 100);
        const floor = new THREE.Mesh(floorGeo, floorMaterial);
        floor.rotation.x = -Math.PI / 2;
        floor.receiveShadow = true;
        scene.add(floor);

        // Base Group
        const baseGroup = new THREE.Group();
        houseGroup.add(baseGroup);

        // Main Body (Cube)
        const bodyGeo = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        baseGroup.add(body);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align square base
        roof.castShadow = true;
        baseGroup.add(roof);

        // Windows
        const windowGeo = new THREE.BoxGeometry(2, 2, 0.2);

        // Front Windows
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(1, 4, 4.1);
        baseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(-1, 4, 4.1);
        baseGroup.add(win2);

        // Back Windows
        const win3 = new THREE.Mesh(windowGeo, windowMaterial);
        win3.position.set(1, 4, -4.1);
        baseGroup.add(win3);

        const win4 = new THREE.Mesh(windowGeo, windowMaterial);
        win4.position.set(-1, 4, -4.1);
        baseGroup.add(win4);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.5);
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x8B0000 }); // Dark Red
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 2, 4.25);
        baseGroup.add(door);

        // Chimney
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, roofMaterial);
        chimney.position.set(3, 9, 0);
        chimney.castShadow = true;
        baseGroup.add(chimney);

        // Add House to Scene
        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your browser.

### Features included:
*   **3D Geometry:** Constructed using basic shapes (Box, Cone, Plane) to form a house structure.
*   **Lighting:** Includes ambient light and a directional light that casts realistic shadows.
*   **Interactivity:** You can **click and drag** to rotate around the house, and **scroll** to zoom in and out.
*   **Materials:** Different colors for walls, roof, grass, and windows.
*   **Responsive:** The canvas resizes automatically if you change the browser window size.

*Note: This code uses a CDN (unpkg) to load the Three.js library. You need an active internet connection for the 3D library to load.*
